import{_ as a,o as i,c as r,ah as l}from"./chunks/framework.C9w-yEnC.js";const p=JSON.parse('{"title":"{Shimera} Current Technical Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/architecture/technical_architecture.md","filePath":"devdoc/architecture/technical_architecture.md"}'),t={name:"devdoc/architecture/technical_architecture.md"};function n(o,e,c,s,d,h){return i(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="shimera-current-technical-architecture" tabindex="-1"><strong>{Shimera} Current Technical Architecture</strong> <a class="header-anchor" href="#shimera-current-technical-architecture" aria-label="Permalink to “{Shimera} Current Technical Architecture”">​</a></h1><blockquote><p>A factual, implementation-level view of Shimera architecture based on the current codebase.</p></blockquote><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to “Table of Contents”">​</a></h2><ol><li><a href="#architecture-overview">Architecture Overview</a></li><li><a href="#core-modules">Core Modules</a></li><li><a href="#rendering-pipeline">Rendering Pipeline</a></li><li><a href="#dependencies">Dependencies</a></li><li><a href="#internal-data-flows">Internal Data Flows</a></li><li><a href="#build-system">Build System</a></li><li><a href="#versioning-strategy">Versioning Strategy</a></li><li><a href="#current-constraints">Current Constraints</a></li><li><a href="#references">References</a></li></ol><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to “Architecture Overview”">​</a></h2><p>Shimera uses a backend abstraction to run the same post-processing workflow on multiple ecosystems.</p><p>The architecture follows this layered model:</p><ol><li>Public API and ABI layer (<code>shimera.h</code>, <code>shimera_api.h</code>).</li><li>Backend abstraction layer (<code>IBackend</code>, resource interfaces, <code>BackendFactory</code>).</li><li>Concrete backend adapters (OpenGL, SFML, Raylib, SDL placeholder).</li><li>Effect framework layer (<code>ShaderEffectBase</code>, CRTP <code>ShaderEffect&lt;Derived&gt;</code>).</li><li>Shared support layer (uniform values, lightweight vector types, GL utilities).</li></ol><p>Backend choice is compile-time (build target + preprocessor define), not runtime plugin selection.</p><h2 id="core-modules" tabindex="-1">Core Modules <a class="header-anchor" href="#core-modules" aria-label="Permalink to “Core Modules”">​</a></h2><h3 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to “Public API Surface”">​</a></h3><p>Main entry points:</p><ul><li><code>include/shimera.h</code></li><li><code>include/shimera_api.h</code></li></ul><p>Responsibilities:</p><ul><li>Provide a compact public include entry point.</li><li>Handle symbol export/import for static or shared builds.</li></ul><h3 id="backend-abstraction-layer" tabindex="-1">Backend Abstraction Layer <a class="header-anchor" href="#backend-abstraction-layer" aria-label="Permalink to “Backend Abstraction Layer”">​</a></h3><p>Key files:</p><ul><li><code>include/backend/IBackend.hpp</code></li><li><code>include/backend/BackendFactory.hpp</code></li><li><code>src/backend/BackendFactory.cpp</code></li></ul><p>Responsibilities:</p><ul><li>Define abstract creation contracts for framebuffers, textures, shaders, and post-processors.</li><li>Hide concrete backend types behind interfaces.</li><li>Select implementation with one backend macro: <ul><li><code>SHIMERA_BACKEND_OPENGL</code></li><li><code>SHIMERA_BACKEND_SFML</code></li><li><code>SHIMERA_BACKEND_RAYLIB</code></li><li><code>SHIMERA_BACKEND_SDL</code> (currently placeholder path)</li></ul></li></ul><h3 id="resource-interfaces" tabindex="-1">Resource Interfaces <a class="header-anchor" href="#resource-interfaces" aria-label="Permalink to “Resource Interfaces”">​</a></h3><ul><li><code>IFrameBuffer</code>: render target lifecycle, resize, texture access.</li><li><code>IPostProcessor</code>: fullscreen post-process pass orchestration.</li><li><code>IShader</code>: shader bind/unbind and typed uniform writes.</li><li><code>ITexture</code>: texture bind/unbind and native-handle bridge.</li></ul><h3 id="concrete-backends" tabindex="-1">Concrete Backends <a class="header-anchor" href="#concrete-backends" aria-label="Permalink to “Concrete Backends”">​</a></h3><ol><li>OpenGL backend (<code>src/backend/opengl/*</code>)</li></ol><ul><li>Native GL ownership for framebuffers, textures, shaders, and fullscreen passes.</li></ul><ol start="2"><li>SFML backend (<code>src/backend/sfml/*</code>)</li></ol><ul><li>Scene capture through <code>sf::RenderTexture</code>.</li><li>Post-processing still executed through OpenGL-based fullscreen pass code.</li></ul><ol start="3"><li>Raylib backend (<code>src/backend/raylib/*</code>)</li></ol><ul><li>Scene capture through <code>RenderTexture2D</code>.</li><li>Post-processing still executed through OpenGL-based fullscreen pass code.</li></ul><ol start="4"><li>SDL backend</li></ol><ul><li>Build target and macro path exist.</li><li>Factory path is placeholder and does not instantiate a concrete backend.</li></ul><h3 id="effect-framework" tabindex="-1">Effect Framework <a class="header-anchor" href="#effect-framework" aria-label="Permalink to “Effect Framework”">​</a></h3><p>Key files:</p><ul><li><code>include/effects/ShaderEffectBase.hpp</code></li><li><code>include/effects/ShaderEffect.inl</code></li><li><code>src/effects/*.cpp</code></li></ul><p>Design:</p><ul><li>Stateful effect classes wrapping one post-processor each.</li><li>CRTP-based fluent API (<code>ShaderEffect&lt;Derived&gt;</code>).</li><li>Shared execution pattern: <ul><li><code>render(texture)</code></li><li><code>render(texture, framebuffer)</code></li></ul></li></ul><p>Built-in effects in current code:</p><ul><li>Brightness</li><li>Contrast</li><li>Saturation</li><li>Grayscale</li><li>Colorshift</li><li>Distortion</li><li>Vignette</li><li>Chromatic Aberration</li></ul><h2 id="rendering-pipeline" tabindex="-1">Rendering Pipeline <a class="header-anchor" href="#rendering-pipeline" aria-label="Permalink to “Rendering Pipeline”">​</a></h2><p>The runtime pipeline is pass-oriented and uses offscreen framebuffers.</p><h3 id="stage-1-scene-capture" tabindex="-1">Stage 1: Scene Capture <a class="header-anchor" href="#stage-1-scene-capture" aria-label="Permalink to “Stage 1: Scene Capture”">​</a></h3><ol><li>Bind framebuffer A.</li><li>Render scene/application draw calls.</li><li>Unbind framebuffer A.</li></ol><h3 id="stage-2-post-process-pass" tabindex="-1">Stage 2: Post-Process Pass <a class="header-anchor" href="#stage-2-post-process-pass" aria-label="Permalink to “Stage 2: Post-Process Pass”">​</a></h3><ol><li>Read framebuffer texture from previous stage.</li><li>Update effect uniforms.</li><li>Draw a fullscreen quad with shader pass.</li></ol><h3 id="stage-3-presentation" tabindex="-1">Stage 3: Presentation <a class="header-anchor" href="#stage-3-presentation" aria-label="Permalink to “Stage 3: Presentation”">​</a></h3><ul><li>Output either to screen or to another framebuffer.</li><li>Enables pass chaining (ping-pong) for multi-effect pipelines.</li></ul><h3 id="common-shader-pass-contract" tabindex="-1">Common Shader Pass Contract <a class="header-anchor" href="#common-shader-pass-contract" aria-label="Permalink to “Common Shader Pass Contract”">​</a></h3><ul><li>Vertex pass consumes fullscreen positions + UV.</li><li>Fragment pass samples <code>u_screenTexture</code> (texture unit 0) and applies effect uniforms.</li></ul><h3 id="typical-flows" tabindex="-1">Typical Flows <a class="header-anchor" href="#typical-flows" aria-label="Permalink to “Typical Flows”">​</a></h3><p>Single-pass:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Scene -&gt; Framebuffer A -&gt; Effect Pass -&gt; Screen</span></span></code></pre></div><p>Two-pass ping-pong:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Scene -&gt; Framebuffer A -&gt; Effect 1 -&gt; Framebuffer B -&gt; Effect 2 -&gt; Screen</span></span></code></pre></div><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to “Dependencies”">​</a></h2><p>Shimera dependencies are split by backend target in Xmake.</p><h3 id="build-declared-packages" tabindex="-1">Build-Declared Packages <a class="header-anchor" href="#build-declared-packages" aria-label="Permalink to “Build-Declared Packages”">​</a></h3><ul><li><code>glew</code></li><li><code>sfml</code> (optional)</li><li><code>raylib</code> (optional)</li><li><code>libsdl3</code> (optional)</li></ul><h3 id="backend-target-matrix" tabindex="-1">Backend Target Matrix <a class="header-anchor" href="#backend-target-matrix" aria-label="Permalink to “Backend Target Matrix”">​</a></h3><table tabindex="0"><thead><tr><th>Target</th><th>Define</th><th>Packages</th><th>Status</th></tr></thead><tbody><tr><td><code>shimera-opengl</code></td><td><code>SHIMERA_BACKEND_OPENGL</code></td><td><code>glew</code></td><td>Implemented</td></tr><tr><td><code>shimera-sfml</code></td><td><code>SHIMERA_BACKEND_SFML</code></td><td><code>glew</code>, <code>sfml</code></td><td>Implemented</td></tr><tr><td><code>shimera-raylib</code></td><td><code>SHIMERA_BACKEND_RAYLIB</code></td><td><code>glew</code>, <code>raylib</code></td><td>Implemented</td></tr><tr><td><code>shimera-sdl</code></td><td><code>SHIMERA_BACKEND_SDL</code></td><td><code>glew</code>, <code>libsdl3</code></td><td>Build path exists, runtime backend incomplete</td></tr></tbody></table><h3 id="opengl-and-glew-in-current-architecture" tabindex="-1">OpenGL and GLEW in Current Architecture <a class="header-anchor" href="#opengl-and-glew-in-current-architecture" aria-label="Permalink to “OpenGL and GLEW in Current Architecture”">​</a></h3><p>Even with SFML or Raylib backend variants, post-processing execution remains OpenGL-driven.</p><p>Practical consequence:</p><ul><li>GLEW and platform OpenGL system libraries are still foundational dependencies for all current backend variants.</li></ul><h2 id="internal-data-flows" tabindex="-1">Internal Data Flows <a class="header-anchor" href="#internal-data-flows" aria-label="Permalink to “Internal Data Flows”">​</a></h2><p>Shimera behavior is best understood through 5 data-flow tracks.</p><h3 id="_1-control-flow" tabindex="-1">1) Control Flow <a class="header-anchor" href="#_1-control-flow" aria-label="Permalink to “1) Control Flow”">​</a></h3><ul><li>App initializes context/window stack.</li><li>App creates backend (<code>BackendFactory::create</code>).</li><li>App creates framebuffers and effects.</li><li>Each frame: scene capture -&gt; pass chain -&gt; presentation.</li></ul><h3 id="_2-render-target-flow" tabindex="-1">2) Render-Target Flow <a class="header-anchor" href="#_2-render-target-flow" aria-label="Permalink to “2) Render-Target Flow”">​</a></h3><ul><li><code>IFrameBuffer::bind/unbind</code> routes draw output to the selected target.</li><li>Semantics differ by backend implementation (OpenGL FBO, SFML render texture, Raylib texture mode).</li></ul><h3 id="_3-texture-flow" tabindex="-1">3) Texture Flow <a class="header-anchor" href="#_3-texture-flow" aria-label="Permalink to “3) Texture Flow”">​</a></h3><ul><li>Framebuffer output is exposed as <code>ITexture</code>.</li><li>Post-processors consume that texture as pass input.</li><li>Pass output becomes next stage input for chaining.</li></ul><h3 id="_4-uniform-flow" tabindex="-1">4) Uniform Flow <a class="header-anchor" href="#_4-uniform-flow" aria-label="Permalink to “4) Uniform Flow”">​</a></h3><ul><li>Effect fields are pushed every render call through <code>setUniform</code>.</li><li>Values travel through <code>UniformValue</code> variant and backend shader dispatch.</li><li>Shader classes cache uniform locations to reduce repeated lookups.</li></ul><h3 id="_5-lifetime-flow" tabindex="-1">5) Lifetime Flow <a class="header-anchor" href="#_5-lifetime-flow" aria-label="Permalink to “5) Lifetime Flow”">​</a></h3><ul><li>Effects own processors.</li><li>Processors own shader objects.</li><li>Framebuffers own texture wrappers.</li><li>Resource release follows object lifetime hierarchy.</li></ul><h2 id="build-system" tabindex="-1">Build System <a class="header-anchor" href="#build-system" aria-label="Permalink to “Build System”">​</a></h2><p>Shimera uses Xmake (<code>xmake.lua</code>) with a target-per-backend strategy.</p><h3 id="global-build-settings" tabindex="-1">Global Build Settings <a class="header-anchor" href="#global-build-settings" aria-label="Permalink to “Global Build Settings”">​</a></h3><ul><li>Build modes: debug/release.</li><li>C++ standard: C++23.</li><li>Windows toolchain policy: MSVC.</li></ul><h3 id="top-level-options" tabindex="-1">Top-Level Options <a class="header-anchor" href="#top-level-options" aria-label="Permalink to “Top-Level Options”">​</a></h3><ul><li><code>shared</code> (default: false): build shared or static library.</li><li><code>examples</code> (default: true): include example applications.</li></ul><h3 id="example-subsystem" tabindex="-1">Example Subsystem <a class="header-anchor" href="#example-subsystem" aria-label="Permalink to “Example Subsystem”">​</a></h3><p>When enabled, example targets are included for OpenGL, SFML, Raylib, and SDL. Each example depends on its corresponding library backend target.</p><h3 id="platform-link-policy" tabindex="-1">Platform Link Policy <a class="header-anchor" href="#platform-link-policy" aria-label="Permalink to “Platform Link Policy”">​</a></h3><p>OpenGL system libraries are linked per platform:</p><ul><li>Windows: <code>opengl32</code></li><li>macOS: <code>OpenGL</code> framework</li><li>Linux/Unix-like: <code>GL</code></li></ul><h2 id="versioning-strategy" tabindex="-1">Versioning Strategy <a class="header-anchor" href="#versioning-strategy" aria-label="Permalink to “Versioning Strategy”">​</a></h2><p>Current workflow uses branch-driven integration and tag-driven releases.</p><h3 id="branch-model" tabindex="-1">Branch Model <a class="header-anchor" href="#branch-model" aria-label="Permalink to “Branch Model”">​</a></h3><p>Long-lived branches:</p><ul><li><code>dev</code> (active integration branch)</li><li><code>master</code> (stable-facing branch)</li></ul><p>Short-lived branch naming commonly uses:</p><ul><li><code>feat/*</code></li><li><code>fix/*</code></li><li><code>chore/*</code></li></ul><h3 id="commit-and-merge-style" tabindex="-1">Commit and Merge Style <a class="header-anchor" href="#commit-and-merge-style" aria-label="Permalink to “Commit and Merge Style”">​</a></h3><ul><li>PR merge commits are retained in history.</li><li>Conventional-style prefixes are commonly used (<code>feat</code>, <code>fix</code>, <code>docs</code>, <code>ci</code>, <code>build</code>, etc.), but not strictly uniform.</li></ul><h3 id="ci-cd-version-triggering" tabindex="-1">CI/CD Version Triggering <a class="header-anchor" href="#ci-cd-version-triggering" aria-label="Permalink to “CI/CD Version Triggering”">​</a></h3><ul><li>CI runs on push/PR for main working branches.</li><li>Release workflow is tag-triggered with <code>v*</code> pattern.</li><li>Pre-release is inferred when the tag contains <code>-</code> (for example <code>v1.2.0-rc1</code>).</li><li>Release artifacts include platform and version in filename.</li></ul><h2 id="current-constraints" tabindex="-1">Current Constraints <a class="header-anchor" href="#current-constraints" aria-label="Permalink to “Current Constraints”">​</a></h2><p>The current implementation has known constraints relevant for roadmap planning:</p><ol><li>SDL backend path is not fully implemented.</li><li><code>SFMLBackend::createTexture</code> and <code>RaylibBackend::createTexture</code> are incomplete.</li><li>Post-processor and shader logic is duplicated across backend implementations.</li><li>Effect shader paths are hardcoded relative paths in constructors.</li></ol><p>These constraints do not invalidate the architecture pattern, but they impact maintainability and packaging robustness.</p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to “References”">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/Application_binary_interface" target="_blank" rel="noreferrer">Application binary interface (ABI)</a></li><li><a href="https://en.wikipedia.org/wiki/Curiously_recurring_template_pattern" target="_blank" rel="noreferrer">Curiously recurring template pattern (CRTP)</a></li><li><a href="https://xmake.io/guide/introduction.html" target="_blank" rel="noreferrer">Xmake Manual</a></li><li><a href="https://www.conventionalcommits.org/en/v1.0.0/" target="_blank" rel="noreferrer">Conventional Commits</a></li></ul>',103)])])}const f=a(t,[["render",n]]);export{p as __pageData,f as default};
